--
-- Name: vw_ai_revenue; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_ai_revenue AS
 SELECT d.fiscal_year,
    d.fiscal_quarter,
    d.quarter_label,
    p.product_name,
    round(sum(fr.revenue_usd_millions), 0) AS revenue_m
   FROM ((public.fact_revenue fr
     JOIN public.dim_product p ON ((fr.product_key = p.product_key)))
     JOIN public.dim_date d ON ((fr.date_key = d.date_key)))
  GROUP BY d.fiscal_year, d.fiscal_quarter, d.quarter_label, p.product_name;


ALTER VIEW public.vw_ai_revenue OWNER TO postgres;

--
-- Name: vw_executive_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_executive_summary AS
 WITH base AS (
         SELECT d.fiscal_year,
            d.fiscal_quarter,
            d.quarter_label,
            sum(f.revenue_usd_millions) AS total_revenue_millions,
            sum(f.gross_profit_usd_millions) AS total_gross_profit_millions,
            round(((sum(f.gross_profit_usd_millions) / NULLIF(sum(f.revenue_usd_millions), (0)::numeric)) * (100)::numeric), 2) AS blended_gross_margin_pct,
            sum(
                CASE
                    WHEN ((p.product_name)::text = 'Services'::text) THEN f.revenue_usd_millions
                    ELSE (0)::numeric
                END) AS services_revenue_millions,
            sum(
                CASE
                    WHEN ((p.product_name)::text = 'iPhone'::text) THEN f.revenue_usd_millions
                    ELSE (0)::numeric
                END) AS iphone_revenue_millions,
            sum(
                CASE
                    WHEN ((p.product_category)::text = 'Hardware'::text) THEN f.revenue_usd_millions
                    ELSE (0)::numeric
                END) AS hardware_revenue_millions
           FROM ((public.fact_revenue f
             JOIN public.dim_date d ON ((f.date_key = d.date_key)))
             JOIN public.dim_product p ON ((f.product_key = p.product_key)))
          GROUP BY d.fiscal_year, d.fiscal_quarter, d.quarter_label
        )
 SELECT fiscal_year,
    fiscal_quarter,
    quarter_label,
    total_revenue_millions,
    total_gross_profit_millions,
    blended_gross_margin_pct,
    services_revenue_millions,
    iphone_revenue_millions,
    hardware_revenue_millions,
    round(((services_revenue_millions / NULLIF(total_revenue_millions, (0)::numeric)) * (100)::numeric), 2) AS services_mix_pct,
    lag(total_revenue_millions) OVER (ORDER BY fiscal_year, fiscal_quarter) AS prior_qtr_revenue,
    round((((total_revenue_millions - lag(total_revenue_millions) OVER (ORDER BY fiscal_year, fiscal_quarter)) / NULLIF(lag(total_revenue_millions) OVER (ORDER BY fiscal_year, fiscal_quarter), (0)::numeric)) * (100)::numeric), 2) AS qoq_growth_pct,
    sum(total_revenue_millions) OVER (ORDER BY fiscal_year, fiscal_quarter ROWS BETWEEN 3 PRECEDING AND CURRENT ROW) AS ttm_revenue_millions
   FROM base
  ORDER BY fiscal_year, fiscal_quarter;


ALTER VIEW public.vw_executive_summary OWNER TO postgres;

--
-- Name: vw_product_margin; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_product_margin AS
 SELECT d.fiscal_year,
    d.fiscal_quarter,
    d.quarter_label,
    p.product_name,
    p.product_category,
    p.gross_margin_tier,
    sum(f.revenue_usd_millions) AS revenue_usd_millions,
    sum(f.gross_profit_usd_millions) AS gross_profit_usd_millions,
    round(avg(f.gross_margin_pct), 2) AS gross_margin_pct,
    sum(f.units_millions) AS units_millions,
    round(((sum(f.revenue_usd_millions) / NULLIF(sum(sum(f.revenue_usd_millions)) OVER (PARTITION BY d.fiscal_year, d.fiscal_quarter), (0)::numeric)) * (100)::numeric), 2) AS revenue_mix_pct,
    sum(sum(f.revenue_usd_millions)) OVER (PARTITION BY d.fiscal_year, p.product_name ORDER BY d.fiscal_quarter ROWS UNBOUNDED PRECEDING) AS ytd_revenue_millions
   FROM ((public.fact_revenue f
     JOIN public.dim_date d ON ((f.date_key = d.date_key)))
     JOIN public.dim_product p ON ((f.product_key = p.product_key)))
  GROUP BY d.fiscal_year, d.fiscal_quarter, d.quarter_label, p.product_name, p.product_category, p.gross_margin_tier;


