--
-- Name: vw_regional_kpi; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_regional_kpi AS
 WITH rt AS (
         SELECT d.fiscal_year,
            d.fiscal_quarter,
            d.quarter_label,
            r.region_name,
            r.region_code,
            r.is_high_growth,
            sum(f.revenue_usd_millions) AS revenue_usd_millions,
            sum(f.gross_profit_usd_millions) AS gross_profit_usd_millions,
            round(avg(f.gross_margin_pct), 2) AS avg_margin_pct
           FROM ((public.fact_revenue f
             JOIN public.dim_date d ON ((f.date_key = d.date_key)))
             JOIN public.dim_region r ON ((f.region_key = r.region_key)))
          GROUP BY d.fiscal_year, d.fiscal_quarter, d.quarter_label, r.region_name, r.region_code, r.is_high_growth
        ), gt AS (
         SELECT rt.fiscal_year,
            rt.fiscal_quarter,
            sum(rt.revenue_usd_millions) AS global_rev_m
           FROM rt
          GROUP BY rt.fiscal_year, rt.fiscal_quarter
        ), lp AS (
         SELECT rt.fiscal_year,
            rt.fiscal_quarter,
            rt.quarter_label,
            rt.region_name,
            rt.region_code,
            rt.is_high_growth,
            rt.revenue_usd_millions,
            rt.gross_profit_usd_millions,
            rt.avg_margin_pct,
            lag(rt.revenue_usd_millions) OVER (PARTITION BY rt.region_name ORDER BY rt.fiscal_year, rt.fiscal_quarter) AS prior_rev
           FROM rt
        )
 SELECT lp.fiscal_year,
    lp.fiscal_quarter,
    lp.quarter_label,
    lp.region_name,
    lp.region_code,
    lp.is_high_growth,
    lp.revenue_usd_millions,
    lp.gross_profit_usd_millions,
    lp.avg_margin_pct,
    lp.prior_rev,
    gt.global_rev_m,
    round(((lp.revenue_usd_millions / NULLIF(gt.global_rev_m, (0)::numeric)) * (100)::numeric), 2) AS region_share_pct,
        CASE
            WHEN (lp.prior_rev > (0)::numeric) THEN round((((lp.revenue_usd_millions - lp.prior_rev) / lp.prior_rev) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS qoq_growth_pct
   FROM (lp
     JOIN gt ON (((lp.fiscal_year = gt.fiscal_year) AND (lp.fiscal_quarter = gt.fiscal_quarter))));


ALTER VIEW public.vw_regional_kpi OWNER TO postgres;

--
-- Name: vw_services_growth; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_services_growth AS
 WITH svc AS (
         SELECT d.fiscal_year,
            d.fiscal_quarter,
            d.quarter_label,
            sum(f.revenue_usd_millions) AS services_rev_m,
            sum(f.gross_profit_usd_millions) AS services_gp_m,
            avg(f.gross_margin_pct) AS services_margin_pct
           FROM ((public.fact_revenue f
             JOIN public.dim_date d ON ((f.date_key = d.date_key)))
             JOIN public.dim_product p ON ((f.product_key = p.product_key)))
          WHERE ((p.product_name)::text = 'Services'::text)
          GROUP BY d.fiscal_year, d.fiscal_quarter, d.quarter_label
        ), tot AS (
         SELECT d.fiscal_year,
            d.fiscal_quarter,
            sum(f.revenue_usd_millions) AS total_rev_m
           FROM (public.fact_revenue f
             JOIN public.dim_date d ON ((f.date_key = d.date_key)))
          GROUP BY d.fiscal_year, d.fiscal_quarter
        )
 SELECT s.fiscal_year,
    s.fiscal_quarter,
    s.quarter_label,
    s.services_rev_m,
    s.services_gp_m,
    s.services_margin_pct,
    t.total_rev_m,
    round(((s.services_rev_m / NULLIF(t.total_rev_m, (0)::numeric)) * (100)::numeric), 2) AS services_attach_rate_pct,
    round((((s.services_rev_m - lag(s.services_rev_m) OVER (ORDER BY s.fiscal_year, s.fiscal_quarter)) / NULLIF(lag(s.services_rev_m) OVER (ORDER BY s.fiscal_year, s.fiscal_quarter), (0)::numeric)) * (100)::numeric), 2) AS services_qoq_growth_pct
   FROM (svc s
     JOIN tot t ON (((s.fiscal_year = t.fiscal_year) AND (s.fiscal_quarter = t.fiscal_quarter))))
  ORDER BY s.fiscal_year, s.fiscal_quarter;


ALTER VIEW public.vw_services_growth OWNER TO postgres;

--
-- Name: vw_yoy_revenue; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_yoy_revenue AS
 WITH base AS (
         SELECT d.fiscal_year,
            d.fiscal_quarter,
            d.quarter_label,
            p.product_name,
            p.product_category,
            r.region_name,
            sum(f.revenue_usd_millions) AS revenue_usd_millions,
            sum(f.gross_profit_usd_millions) AS gross_profit_usd_millions,
            avg(f.gross_margin_pct) AS avg_gross_margin_pct,
            sum(f.units_millions) AS units_millions
           FROM (((public.fact_revenue f
             JOIN public.dim_date d ON ((f.date_key = d.date_key)))
             JOIN public.dim_product p ON ((f.product_key = p.product_key)))
             JOIN public.dim_region r ON ((f.region_key = r.region_key)))
          GROUP BY d.fiscal_year, d.fiscal_quarter, d.quarter_label, p.product_name, p.product_category, r.region_name
        ), lagged AS (
         SELECT base.fiscal_year,
            base.fiscal_quarter,
            base.quarter_label,
            base.product_name,
            base.product_category,
            base.region_name,
            base.revenue_usd_millions,
            base.gross_profit_usd_millions,
            base.avg_gross_margin_pct,
            base.units_millions,
            lag(base.revenue_usd_millions, 4) OVER (PARTITION BY base.product_name, base.region_name ORDER BY base.fiscal_year, base.fiscal_quarter) AS prior_rev
           FROM base
        )
 SELECT fiscal_year,
    fiscal_quarter,
    quarter_label,
    product_name,
    product_category,
    region_name,
    revenue_usd_millions,
    gross_profit_usd_millions,
    avg_gross_margin_pct,
    units_millions,
    prior_rev,
        CASE
            WHEN (prior_rev > (0)::numeric) THEN round((((revenue_usd_millions - prior_rev) / prior_rev) * (100)::numeric), 2)
            ELSE NULL::numeric
        END AS yoy_growth_pct,
    round((revenue_usd_millions - COALESCE(prior_rev, (0)::numeric)), 2) AS yoy_delta_m
   FROM lagged;


ALTER VIEW public.vw_yoy_revenue OWNER TO postgres;

